-- Fix news_reactions: rename 'type' to 'reaction'
ALTER TABLE news_reactions ADD COLUMN `reaction` varchar(16) NOT NULL DEFAULT 'like';
UPDATE news_reactions SET `reaction` = `type`;
ALTER TABLE news_reactions DROP COLUMN `type`;

